const raw = $json.stdout || $json.data || $json.response || '';
const now = new Date().toISOString();
const caddyActive = /active/.test(raw.split('--- CADDY ---')[1] || '');
const loopback = /127\.0\.0\.1:18789|127\.0\.0\.1:18791/.test(raw);
const healthy = loopback && !caddyActive;
const status = healthy ? 'Healthy' : 'Needs Attention';
const emoji = healthy ? '✅' : '🚨';
const blocks = [
  { type: 'header', text: { type: 'plain_text', text: `${emoji} Security Gateway Weekly` } },
  { type: 'context', elements: [ { type: 'mrkdwn', text: `*Checked:* ${now}` }, { type: 'mrkdwn', text: `*Status:* ${status}` } ] },
  { type: 'divider' },
  { type: 'section', fields: [
    { type: 'mrkdwn', text: `*Loopback Bindings*\n${loopback ? 'Yes' : 'No'}` },
    { type: 'mrkdwn', text: `*Caddy*\n${caddyActive ? 'Active' : 'Inactive'}` }
  ] }
];
if (!healthy) blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*Next Step*\n${loopback ? 'Disable Caddy.' : 'Restore localhost bindings and verify gateway.'}` } });
return [{ json: { checkedAt: now, healthy, status, slackText: `${emoji} Security gateway weekly: ${status}`, slackBlocks: blocks } }];
